// Normalize Jira subtask webhook payload
const body = $json.body || $json;
const issue = body.issue || {};
const fields = issue.fields || {};

// Check if this is a subtask
const issueType = fields.issuetype?.name?.toLowerCase() || '';
const isSubtask = issueType === 'subtask' || issueType === 'sub-task';

if (!isSubtask) {
  return [{ json: { isSubtask: false, skip: true, reason: 'Not a subtask' } }];
}

// Extract agent label from issue labels
const labels = fields.labels || [];
const agentLabel = labels.find(l => l.startsWith('agent:'));

// Skip if no agent label - this is not an automated subtask
if (!agentLabel) {
  return [{ json: { isSubtask: false, skip: true, reason: 'No agent label found' } }];
}

// Agent label mapping
const agentLabelMap = {
  'agent:planner': 'engineer-planner',
  'agent:implementer': 'engineer-implementer',
  'agent:reviewer': 'engineer-reviewer',
  'agent:pm': 'product-manager',
  'agent:ui': 'ui-engineer',
  'agent:marketing': 'marketing',
  'agent:creative-assets': 'creative-assets',
  'agent:bug-triage': 'bug-triage',
  'agent:security': 'security-agent',
  'agent:sprint-report': 'sprint-reporter',
  'agent:standup': 'sprint-reporter'
};

const agent = agentLabelMap[agentLabel] || 'engineer-implementer';

// Get parent issue key
const parentKey = fields.parent?.key || null;

// Determine if this agent produces code and should route through pipeline
// Engineering agents get worktree sharing + auto-merge via pipeline engine
const pipelineAgents = {
  'engineer-implementer': 'subtask',
  'ui-engineer': 'subtask',
  'security-agent': 'security-fix',
  'e2e-builder': 'subtask'
};
const pipelineType = pipelineAgents[agent] || null;

return [{
  json: {
    isSubtask: true,
    issueKey: issue.key,
    parentKey: parentKey,
    summary: fields.summary || '',
    description: fields.description || '',
    agent: agent,
    agentLabel: agentLabel,
    labels: labels,
    status: fields.status?.name || 'To Do',
    projectKey: issue.key?.split('-')[0] || 'CER',
    webhookEvent: body.webhookEvent || 'jira:issue_updated',
    timestamp: body.timestamp,
    pipelineType: pipelineType,
    usePipeline: !!pipelineType
  }
}];

// Check if subtask should be triggered (status = To Do, or just created)
const status = $json.status?.toLowerCase() || '';
const webhookEvent = $json.webhookEvent || '';

// Trigger conditions:
// 1. Subtask just created and status is 'To Do'
// 2. Subtask transitioned to 'To Do' (for retries)
// 3. Issue has no blocking links (checked separately)

const shouldTrigger = 
  status === 'to do' || 
  status === 'open' || 
  webhookEvent.includes('created');

return [{
  json: {
    ...$json,
    shouldTrigger: shouldTrigger,
    triggerReason: shouldTrigger ? 
      (webhookEvent.includes('created') ? 'subtask_created' : 'subtask_ready') : 
      'not_ready'
  }
}];

// Check if this subtask has unresolved blockers
const issueLinks = $json.fields?.issuelinks || [];
const originalData = $('Check trigger condition').first().json;

// Find "is blocked by" links
const blockers = issueLinks.filter(link => {
  // Jira uses different link types - check for blocked-by relationship
  const linkType = link.type?.name?.toLowerCase() || '';
  const isBlockedBy = linkType.includes('block');

  // The inwardIssue is the blocker (if this issue is blocked BY it)
  const blockerIssue = link.inwardIssue;
  if (!blockerIssue) return false;

  // Check if blocker is resolved/done
  const blockerStatus = blockerIssue.fields?.status?.name?.toLowerCase() || '';
  const isResolved = blockerStatus === 'done' || blockerStatus === 'closed' || blockerStatus === 'resolved';

  return isBlockedBy && !isResolved;
});

const hasUnresolvedBlockers = blockers.length > 0;
const blockerKeys = blockers.map(b => b.inwardIssue?.key).filter(Boolean);

return [{
  json: {
    ...originalData,
    hasBlockers: hasUnresolvedBlockers,
    blockerKeys: blockerKeys,
    canRun: !hasUnresolvedBlockers
  }
}];

// Log that subtask is blocked - will be triggered later when blockers complete
const blockerKeys = $json.blockerKeys || [];

console.log(`Subtask ${$json.issueKey} blocked by: ${blockerKeys.join(', ')}`);

return [{
  json: {
    status: 'blocked',
    issueKey: $json.issueKey,
    blockedBy: blockerKeys,
    message: `Waiting for blockers to complete: ${blockerKeys.join(', ')}`
  }
}];
